insert into public.projects(title,slug,category,status,year,role,image,summary,tags,tools,content) select 'ML-Based Anomaly Detection with Concept Drift','ml-anomaly-detection-concept-drift','AI / Machine Learning','Academic Research','2026','Researcher & Developer','assets/svg/ai-drift.svg','A streaming machine learning research project focused on detecting anomalies when behaviour changes over time.',array['Python','Scikit-learn','River','Streaming ML']::text[],'Python, Scikit-learn, River, Pandas, Matplotlib','{"overview": "This MSc research direction explores how anomaly detection systems can stay accurate when incoming data patterns shift over time. Traditional static models often lose performance when real-world behaviour changes, so this project studies concept drift-aware detection and evaluation.", "problem": "Static anomaly detectors can become unreliable when the underlying data distribution changes. In security, finance, infrastructure and IoT systems, this can lead to missed threats or excessive false alarms.", "solution": "The project uses streaming data preparation, model training, drift monitoring and comparative evaluation to identify when models need adaptation.", "features": ["Dataset preparation for streaming-style analysis", "Baseline anomaly detection model", "Concept drift monitoring workflow", "Evaluation using precision, recall and false alarm behaviour", "Research-backed implementation roadmap"], "outcome": "A strong MSc project foundation suitable for research, implementation, evaluation and dissertation writing.", "future": "Add dashboard visualisation, live stream simulation, adaptive model retraining and explainable anomaly reports."}'::jsonb where not exists (select 1 from public.projects where slug='ml-anomaly-detection-concept-drift');
insert into public.projects(title,slug,category,status,year,role,image,summary,tags,tools,content) select 'The Miner’s Spice Restaurant Platform','miners-spice-restaurant-platform','Web Systems','Commercial Project','2026','Full-Stack Developer','assets/svg/restaurant.svg','A restaurant website and management system with menu, ordering, admin and customer-facing pages.',array['PHP','MySQL','Admin Dashboard','Ordering']::text[],'PHP, MySQL, HTML, CSS, JavaScript','{"overview": "A commercial restaurant platform designed to support online menu browsing, customer ordering, bookings, gallery pages and backend management.", "problem": "Small restaurants often rely on generic templates that do not manage menu structure, orders and presentation professionally.", "solution": "The platform connects customer-facing pages with backend/admin logic so the restaurant can manage content and orders in one system.", "features": ["Menu sections and item cards", "Online ordering flow", "Booking/contact pages", "Gallery and customer pages", "Admin-linked management structure"], "outcome": "A practical business system that can be customised and sold to restaurants.", "future": "Add payment gateway, kitchen dashboard, order tracking and analytics."}'::jsonb where not exists (select 1 from public.projects where slug='miners-spice-restaurant-platform');
insert into public.projects(title,slug,category,status,year,role,image,summary,tags,tools,content) select 'SmartCV AI CV Analyzer','smartcv-ai-cv-analyzer','AI / Machine Learning','Live / In Progress','2026','Product Builder','assets/svg/smartcv.svg','An AI-supported CV optimisation workspace with ATS feedback, role-fit analysis and subscription logic.',array['AI','ATS','Stripe','CV Analysis']::text[],'AI workflows, Web stack, Stripe, Resume parsing','{"overview": "SmartCV AI is a CV optimisation concept/platform focused on helping candidates improve their CVs through ATS scoring, keyword alignment and improvement suggestions.", "problem": "Many job seekers submit CVs that are not aligned with job descriptions or ATS keyword patterns.", "solution": "The system analyses CV content, compares it with role requirements and provides structured suggestions for improvement.", "features": ["CV upload workflow", "ATS score direction", "Keyword extraction", "Missing keyword detection", "Role-fit feedback", "Subscription-ready product logic"], "outcome": "A strong AI SaaS-style project for job-tech and career support.", "future": "Add job-description matching, rewrite suggestions, dashboard history and recruiter view."}'::jsonb where not exists (select 1 from public.projects where slug='smartcv-ai-cv-analyzer');
insert into public.projects(title,slug,category,status,year,role,image,summary,tags,tools,content) select 'Q-Learning Grid World Agent','q-learning-grid-world-agent','AI / Machine Learning','Academic Project','2026','ML Developer','assets/svg/q-learning.svg','A reinforcement learning coursework project using Q-learning in a 5×5 grid with obstacles and sparse rewards.',array['RL','Q-Learning','Python','AI']::text[],'Python, NumPy, Matplotlib','{"overview": "This project demonstrates reinforcement learning through a grid-world environment where an agent learns to navigate from start to goal using Q-table updates.", "problem": "The agent must learn optimal navigation despite obstacles, sparse rewards and exploration trade-offs.", "solution": "Q-learning with epsilon-greedy exploration is used to compare learning behaviour across different exploration values.", "features": ["5×5 grid environment", "Q-table implementation", "Bellman update rule", "Epsilon comparison", "Reward tracking", "Path optimisation"], "outcome": "A clear academic AI project showing practical reinforcement learning understanding.", "future": "Add visual simulation, animated training steps and comparison charts."}'::jsonb where not exists (select 1 from public.projects where slug='q-learning-grid-world-agent');
insert into public.projects(title,slug,category,status,year,role,image,summary,tags,tools,content) select 'Coursera Digital Transformation Strategy','coursera-digital-transformation-strategy','Academic Projects','Academic Project','2026','Research Analyst','assets/svg/coursera.svg','A digital transformation strategy analysis for Coursera covering AI, data analytics, cloud and EdTech maturity.',array['Digital Strategy','AI','Cloud','EdTech']::text[],'Research, Strategy, Presentation, Data analysis','{"overview": "This project analyses Coursera as a digital education platform and explores its maturity, platform strategy and use of digital technologies.", "problem": "EdTech platforms must adapt to learner expectations, AI personalisation and scalable infrastructure.", "solution": "The strategy reviews AI, big data, learner analytics, cloud systems and recommendation concepts.", "features": ["Digital maturity review", "AI recommendation direction", "Student segmentation concept", "Cloud and LMS analysis", "Platform business model review"], "outcome": "A professional academic strategy project suitable for demonstrating business and technical analysis.", "future": "Add interactive strategy dashboard and competitor benchmarking."}'::jsonb where not exists (select 1 from public.projects where slug='coursera-digital-transformation-strategy');
insert into public.projects(title,slug,category,status,year,role,image,summary,tags,tools,content) select 'Cloud-Native Air Pollution & Respiratory Death Analysis','cloud-air-pollution-respiratory-analysis','Data / Cloud','Academic Project','2026','Data Engineer','assets/svg/cloud-data.svg','A cloud data project analysing average PM2.5 pollution and respiratory deaths using Azure and PySpark.',array['Azure','PySpark','Big Data','Analytics']::text[],'Azure Data Lake Gen2, Synapse Spark, PySpark, Plotly','{"overview": "This project studies the relationship between PM2.5 pollution and respiratory deaths using cloud-native data engineering and analytics workflows.", "problem": "Environmental and health datasets need scalable processing before meaningful insights can be extracted.", "solution": "Raw CSV data is ingested, transformed with Spark, stored as Parquet and analysed through country-level aggregation and visualisation.", "features": ["Azure Data Lake ingestion", "Synapse Spark transformations", "PySpark cleaning and aggregation", "Parquet storage", "Plotly visual analytics", "Geospatial and correlation insight"], "outcome": "A strong big data portfolio project connecting cloud infrastructure with real-world health analytics.", "future": "Add automated ETL pipeline, Power BI dashboard and predictive modelling."}'::jsonb where not exists (select 1 from public.projects where slug='cloud-air-pollution-respiratory-analysis');
insert into public.projects(title,slug,category,status,year,role,image,summary,tags,tools,content) select 'PenTest-Ont Cybersecurity Ontology','pentest-ont-cybersecurity-ontology','Cybersecurity','Academic Project','2026','Security Researcher','assets/svg/cyber-ontology.svg','A cybersecurity ontology modelling tools, techniques, vulnerabilities and penetration testing knowledge.',array['OWL','Protégé','SPARQL','Cybersecurity']::text[],'OWL, Protégé, SPARQL, Knowledge Graphs','{"overview": "PenTest-Ont structures penetration testing knowledge using ontology engineering and semantic technologies.", "problem": "Cybersecurity knowledge can become fragmented across tools, techniques and vulnerability categories.", "solution": "The ontology models relationships between tools, testing techniques, vulnerabilities and reasoning concepts.", "features": ["OWL ontology structure", "Protégé modelling", "SPARQL queries", "Knowledge graph concepts", "Tools and vulnerability mapping", "AI-assisted reasoning direction"], "outcome": "A unique cybersecurity research project showing structured knowledge modelling.", "future": "Connect ontology to automated security reports and AI assistants."}'::jsonb where not exists (select 1 from public.projects where slug='pentest-ont-cybersecurity-ontology');
insert into public.projects(title,slug,category,status,year,role,image,summary,tags,tools,content) select 'AutoMarketPro Car Marketplace','automarketpro-car-marketplace','Web Systems','In Progress','2026','Full-Stack Developer','assets/svg/car-market.svg','A car-selling marketplace with seller ads, subscriptions, Stripe checkout, image uploads and admin moderation.',array['PHP','MySQL','Stripe','Marketplace']::text[],'PHP, MySQL, Stripe, Admin/User Panels','{"overview": "AutoMarketPro is a car marketplace platform inspired by vehicle listing systems, allowing sellers to post ads and manage subscription-based listings.", "problem": "Car-selling platforms need listing control, payment workflows, admin moderation and clean search/filtering.", "solution": "The system connects seller ad posting with subscription packages, Stripe checkout and admin review tools.", "features": ["Seller ad posting", "Subscription packages", "Stripe checkout and webhook direction", "Image upload", "Admin moderation", "User dashboard", "Featured/boosted listing direction"], "outcome": "A monetisable web system with strong commercial potential.", "future": "Add advanced search, valuations, dealer profiles, finance calculator and analytics."}'::jsonb where not exists (select 1 from public.projects where slug='automarketpro-car-marketplace');
insert into public.projects(title,slug,category,status,year,role,image,summary,tags,tools,content) select 'Unity FPS Sniper Contracts Prototype','unity-fps-sniper-contracts-prototype','Game Development','Prototype','2026','Game Developer','assets/svg/unity-fps.svg','A tactical FPS sniper prototype with AI states, missions, vehicles, weapons, ADS and large terrain design.',array['Unity','C#','AI','Level Design']::text[],'Unity, C#, Blender, AI Systems, Vehicle Controller','{"overview": "A sniper contracts-style tactical FPS prototype built in Unity with mission structure, AI behaviour, terrain, vehicles and scoped weapon systems.", "problem": "Tactical shooter prototypes require multiple systems to work together: AI, movement, weapons, mission logic and level design.", "solution": "The project builds modular systems for missions, weapons, vehicles and enemy AI states.", "features": ["Large terrain and mission zones", "AI idle/patrol/alert/combat states", "Weapon ADS and scopes", "Vehicle controller direction", "Mission objective system", "Level design with refinery-style environment"], "outcome": "A serious game development prototype that demonstrates systems thinking and Unity engineering.", "future": "Add polished AI, UI, audio, cinematic intro and Steam-ready vertical slice."}'::jsonb where not exists (select 1 from public.projects where slug='unity-fps-sniper-contracts-prototype');
insert into public.projects(title,slug,category,status,year,role,image,summary,tags,tools,content) select 'Cybersecurity DVWA & Ethical Hacking Labs','dvwa-ethical-hacking-labs','Cybersecurity','Practical Labs','2026','Security Learner','assets/svg/dvwa.svg','Hands-on cybersecurity labs using DVWA, Burp Suite, OWASP concepts and professional reporting practice.',array['DVWA','Burp Suite','OWASP','Security']::text[],'DVWA, Burp Suite, OWASP testing workflow','{"overview": "This lab project demonstrates practical ethical hacking awareness through controlled vulnerable environments and reporting practice.", "problem": "Security concepts are easier to understand when tested in legal, controlled lab environments.", "solution": "DVWA-style workflows are used to practise vulnerability testing, evidence capture and mitigation thinking.", "features": ["OWASP-style vulnerability testing", "Burp Suite workflows", "Evidence screenshots direction", "Risk explanation", "Professional report writing"], "outcome": "A practical cybersecurity learning portfolio section.", "future": "Add full write-ups, remediation steps and lab videos."}'::jsonb where not exists (select 1 from public.projects where slug='dvwa-ethical-hacking-labs');
insert into public.projects(title,slug,category,status,year,role,image,summary,tags,tools,content) select 'Jarvis AI Agent Workflow','jarvis-ai-agent-workflow','AI / Automation','Concept / Prototype','2026','Automation Designer','assets/svg/jarvis.svg','A modular AI assistant workflow concept using n8n-style automation, local models and API actions.',array['AI Agents','n8n','Ollama','Automation']::text[],'n8n, Ollama, Prompting, APIs','{"overview": "Jarvis is a personal assistant concept built around modular AI workflows, automation and action-based tasks.", "problem": "Many daily workflows are repetitive but require context, decision-making and structured tool use.", "solution": "The concept uses agents, prompts, local models and API-style actions to automate productivity tasks.", "features": ["Personal assistant workflow", "n8n-style automation", "Ollama/local model direction", "Prompt modules", "API action planning", "Productivity automation"], "outcome": "A strong AI automation concept for future development.", "future": "Build working agent modules for email, calendar, files, research and project management."}'::jsonb where not exists (select 1 from public.projects where slug='jarvis-ai-agent-workflow');
insert into public.projects(title,slug,category,status,year,role,image,summary,tags,tools,content) select 'Full-Stack Dating App Prototype','full-stack-dating-app-prototype','Web Systems','Prototype','2026','Full-Stack Developer','assets/svg/dating-app.svg','A full-stack app prototype with authentication direction, profile flow, matching concept and database schema planning.',array['React','Node','Prisma','PostgreSQL']::text[],'React, Node.js, Prisma, PostgreSQL','{"overview": "A product-style dating app prototype exploring full-stack structure, user profiles, authentication and matching workflows.", "problem": "Modern dating apps require secure authentication, clean data modelling and smooth profile/matching flows.", "solution": "The prototype plans frontend, backend, Prisma schema and PostgreSQL database structure.", "features": ["Frontend/backend architecture", "Prisma schema direction", "PostgreSQL setup", "Authentication planning", "Profile flow", "Matching concept"], "outcome": "A useful full-stack learning and product design project.", "future": "Add working auth, chat, profile verification and recommendations."}'::jsonb where not exists (select 1 from public.projects where slug='full-stack-dating-app-prototype');
insert into public.projects(title,slug,category,status,year,role,image,summary,tags,tools,content) select 'Blender Animation & VFX Portfolio','blender-animation-vfx-portfolio','3D / VFX / Animation','Creative Portfolio','2026','3D/VFX Artist','assets/svg/blender-vfx.svg','A creative portfolio area for 2D/3D animation, Blender assets, VFX, video editing and modular game/promo visuals.',array['Blender','VFX','Animation','Video Editing']::text[],'Blender, After Effects, Premiere Pro, Unity assets','{"overview": "This creative portfolio section presents Haider’s experience across 2D/3D animation, VFX, video editing and game-ready visual production.", "problem": "Creative technical work needs a polished showcase that connects visual skill with practical production outcomes.", "solution": "The project groups animation, modular assets, VFX and editing work into a professional portfolio format.", "features": ["2D/3D animation", "Blender assets", "VFX compositions", "Video editing", "Modular assets", "Game and promo presentation support"], "outcome": "A creative-technical showcase supporting freelance, game and media opportunities.", "future": "Add showreel video, before/after VFX breakdowns and asset galleries."}'::jsonb where not exists (select 1 from public.projects where slug='blender-animation-vfx-portfolio');
insert into public.projects(title,slug,category,status,year,role,image,summary,tags,tools,content) select 'Family Haven Shopify Store','family-haven-shopify-store','E-commerce / Business','Business Project','2026','Store Builder & Marketer','assets/svg/shopify-store.svg','A UK-focused Shopify pet supplies store with product research, CJ Dropshipping, SEO blogs and paid ad testing.',array['Shopify','CJ Dropshipping','Meta Ads','SEO']::text[],'Shopify, CJ Dropshipping, Meta Ads, Pinterest, SEO blogs','{"overview": "Family Haven is a pet supplies e-commerce store focused on UK customers, product testing and digital marketing.", "problem": "New stores need niche selection, product research, conversion-focused pages and traffic testing.", "solution": "The store uses Shopify, CJ Dropshipping, UK-focused delivery messaging, blogs and paid ad experiments.", "features": ["Shopify store setup", "Pet supplies niche", "Product research", "CJ Dropshipping", "Meta Ads testing", "SEO/blog content", "UK-focused marketing"], "outcome": "A practical e-commerce business project showing product, marketing and store-building skills.", "future": "Add winning product funnel, email automation, reviews and conversion optimisation."}'::jsonb where not exists (select 1 from public.projects where slug='family-haven-shopify-store');
insert into public.blogs(title,slug,category,date,image,summary,content) select 'Building a Portfolio That Shows Both Technical and Creative Skill','technical-creative-portfolio','Career','2026-06-06','assets/svg/blog-portfolio.svg','A short article about presenting AI, cybersecurity, web, game and creative work inside one professional brand.','A strong portfolio should not look like a random list of projects. It should explain identity, direction and proof. For a hybrid profile, the website must make categories clear: AI, cybersecurity, web systems, game development and creative/VFX work. Each project needs a short story: the problem, the solution, the tools and the result. This makes the portfolio useful for jobs, clients and university work at the same time.' where not exists (select 1 from public.blogs where slug='technical-creative-portfolio');
insert into public.blogs(title,slug,category,date,image,summary,content) select 'Why Case Studies Make Projects Look More Professional','why-case-studies-matter','Portfolio','2026-06-06','assets/svg/blog-case-study.svg','Why project detail pages should explain process, challenges and outcomes instead of only showing images.','Project cards are useful for browsing, but case studies build trust. A case study shows how the work was planned, what problem was solved, what tools were used and what outcome was achieved. This is especially important for software, AI and cybersecurity projects because recruiters and clients want to understand the thinking behind the result.' where not exists (select 1 from public.blogs where slug='why-case-studies-matter');
insert into public.blogs(title,slug,category,date,image,summary,content) select 'Combining AI, Cybersecurity and Game Development in One Brand','ai-cybersecurity-game-dev-brand','Personal Brand','2026-06-06','assets/svg/blog-brand.svg','A focused way to connect multiple skills without making the website feel confusing.','A multi-skill portfolio works best when every skill supports one main identity: a technical creator who builds practical digital systems. AI shows research and automation ability. Cybersecurity shows defensive thinking and technical awareness. Game development shows systems, interaction and creative engineering. 3D and VFX show visual communication. Together, they create a strong modern technical brand.' where not exists (select 1 from public.blogs where slug='ai-cybersecurity-game-dev-brand');
